  ('police-8b7f1efc-moex-00527', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '有關「警察」之敘述，下列何者錯誤？', '["警察職權行使法第2條所稱「警察」，係指警察機關與警察人員之總稱", "警察職權行使法第2條所稱「警察」，係指形式意義的警察", "警察法第9條所稱依法行使職權之「警察」，係指警察機關與警察人員之總稱", "憲法第8條第1項所稱「非經司法或警察機關依法定程序不得逮捕拘禁」之「警察」，僅指組 織法上的警察"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "fe419e42d44b", "answer_pdf_sha1": "70c257965827", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1108", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
