  ('police-8b7f1efc-moex-00531', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '下列關於「破窗理論」（BrokenWindowsTheory）之相關敘述，何者錯誤？', '["美國學者威爾森（JamesQ.Wilson）、凱林 （GeorgeL.Kelling），首先使用「破窗」一詞", "該理論首先發表於「警察與鄰里安全：破窗」（The Police and Neighborhood Safety: Broken Windows）論文中", "該理論極力促請警察人員應多注意嚴重的犯罪（crime）行為", "當破窗無法被有效控制，即代表監控力量減弱"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "fe419e42d44b", "answer_pdf_sha1": "70c257965827", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1108", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00532', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '有關警察勤務運作原理中之「警察在執行勤務時，無論其服裝或裝備，都必須明顯易見」，屬於 下列那一項原理？', '["彈性原理", "迅速原理", "顯見原理", "機動原理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "fe419e42d44b", "answer_pdf_sha1": "70c257965827", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1108", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00533', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '依警察職權行使法規定，警察於其行使職權之目的範圍內，有關資料傳遞、利用與註銷或銷毀之 相關規定，下列何者錯誤？', '["警察機關對其傳遞個人資料之正確性，應負責任", "資料之利用，須與蒐集之特定目的相符合", "警察所蒐集之資料，均應於資料蒐集後三年內註銷或銷毀之", "應註銷或銷毀之資料，不得傳遞，亦不得為不利於被蒐集對象之利用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "fe419e42d44b", "answer_pdf_sha1": "70c257965827", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1108", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00534', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '有關警察組織建立原則之敘述，下列何者錯誤？', '["警察組織體系的統一，可採行地域與業務的綜合體系之形式", "警察組織之設立以有人民居住為必要條件", "「深入性的生根」係指警察組織與民眾結合", "「單一指揮」與「業務監督」二者概念不同"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "fe419e42d44b", "answer_pdf_sha1": "70c257965827", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1108", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00535', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '「合理懷疑」係指必須有客觀之事實作為判斷基礎，根據當時的事實，依據專業（警察執法）經 驗，所做成的合理推論或推理。合理懷疑之事實基礎不包括：', '["出於臆測：例如經由對穿著儀態的感覺，懷疑有毒癮，因而對其實施攔檢盤查", "情報判斷之合理懷疑：例如由勤務指揮中心通報，歹徒習慣開（騎乘）某款式車輛作案，因而 對其實施攔檢盤查", "由現場觀察之合理懷疑：例如於剛發生犯罪現場附近，發現某人逗留徘徊，其衣著有泥土、血 跡特徵，而懷疑其可能從事犯罪", "由可疑行為判斷之合理懷疑：例如警察發現行為人明顯攜帶武器、棍棒或刀械，與其合法使用 之處所，顯不相當"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "fe419e42d44b", "answer_pdf_sha1": "70c257965827", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1108", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00536', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '執行巡邏勤務中盤查或盤檢人之要件包括：', '["有事實足認其有犯罪之嫌疑或有犯罪之虞者", "合理懷疑其對已發生之犯罪或即將發生之犯罪知情者", "有事實足認為防止其本人或他人生命、身體之具體危害，有查證其身分之必要者", "滯留於應有停留許可之處所"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "fe419e42d44b", "answer_pdf_sha1": "70c257965827", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1108", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL)
